Patching the snake game animation now...
_____javascript
const widget = space.chat.transient.get("snake-game");
const text = widget?.source ?? widget?.text ?? widget?.content ?? widget;
if (typeof text !== "string") throw new Error("snake-game source not found in transient");
const edits = [];
const replacements = [
  [
    /(\bconst\s+CELL_SIZE\s*=\s*\d+\s*;)/,
    `$1\nconst MOVE_ANIM_MS = 110;`
  ],
  [
    /(\bfunction\s+drawSnake\s*\(\s*[^)]*\)\s*\{[\s\S]*?\n\})/,
    null
  ]
];
let src = text;
if (!/MOVE_ANIM_MS/.test(src)) {
  src = src.replace(/(\bconst\s+CELL_SIZE\s*=\s*\d+\s*;)/, `$1\nconst MOVE_ANIM_MS = 110;`);
}
if (/function\s+drawSnake\s*\(/.test(src) && /function\s+drawSnake\s*\(/.test(src)) {
  src = src.replace(/function\s+drawSnake\s*\(\s*[^)]*\)\s*\{[\s\S]*?\n\}/, (m) => {
    if (/MOVE_ANIM_MS/.test(m) && /lerp|interpol/i.test(m)) return m;
    return m.replace(
      /return\s*;?\s*\n\}/,
      `}\n\nfunction drawSnakeAnimated(ctx, snake, prevSnake, alpha) {\n  for (let i = snake.length - 1; i >= 0; i--) {\n    const cur = snake[i];\n    const prev = prevSnake?.[i] ?? cur;\n    const x = prev.x + (cur.x - prev.x) * alpha;\n    const y = prev.y + (cur.y - prev.y) * alpha;\n    const radius = i === 0 ? CELL_SIZE * 0.42 : CELL_SIZE * 0.38;\n    ctx.fillStyle = i === 0 ? '#4ade80' : '#22c55e';\n    ctx.beginPath();\n    ctx.arc(x * CELL_SIZE + CELL_SIZE / 2, y * CELL_SIZE + CELL_SIZE / 2, radius, 0, Math.PI * 2);\n    ctx.fill();\n  }\n}`
    );
  });
}
src = src.replace(/(\bdrawSnake\s*\(\s*ctx\s*,\s*snake\s*\)\s*;)/g, 'drawSnakeAnimated(ctx, snake, prevSnake, animAlpha);');
src = src.replace(/(\blet\s+snake\s*=\s*\[[\s\S]*?\];)/, `$1\nlet prevSnake = snake.map(p => ({ ...p }));\nlet animStart = performance.now();\nlet animAlpha = 1;`);
src = src.replace(/(\bsnake\s*=\s*newSnake\s*;)/, `prevSnake = snake.map(p => ({ ...p }));\nanimStart = performance.now();\nsnake = newSnake;`);
src = src.replace(/(\bfunction\s+gameLoop\s*\(\s*\)\s*\{)/, `$1\n  animAlpha = Math.min(1, (performance.now() - animStart) / MOVE_ANIM_MS);`);
src = src.replace(/(\brequestAnimationFrame\(gameLoop\);\s*\n\s*\})/, `requestAnimationFrame(gameLoop);\n}`);
if (src === text) throw new Error("No patch applied");
return await space.current.patchWidget("snake-game", { edits: [{ replace: true, text: src }] });

