const widget = await space.current.readWidget("snake-game");
const text = widget?.content ?? widget?.text ?? widget;
const s = typeof text === "string" ? text : JSON.stringify(text);

const oldBlock = /(?:function|const)\s+(?:updateSnake|moveSnake|stepSnake)\b[\s\S]*?(?=\n(?:function|const)\s+\w+\b|\n<\/script>|\nexport\b|$)/m;
const snippet = s.match(oldBlock)?.[0];

