  ? snippet
      .replace(/(snake(?:Segments|Body)?\.unshift\(\s*newHead\s*\);\s*[\s\S]*?)(snake(?:Segments|Body)?\.pop\(\s*\)\s*;)/m,
               `$1/* smooth animation: keep old tail during tween */\n`)
      .replace(/(drawSnake|renderSnake)\s*\(/, `renderSnakeAnimated(`)
  : null;

if (!patch) {
  return "Could not locate snake movement code in the widget.";
}

